-- Baseline initialization data.
-- Keep only roles and demo login users here.
-- Full genealogy demo data is generated by V99__full_realistic_seed_data.sql.

insert into role (role_code, role_name, description)
values
    ('clan_admin', '宗族管理员', '管理宗族空间、成员权限、主数据和审核配置'),
    ('branch_admin', '支派管理员', '管理授权支派范围内的人物、关系、来源和支派数据'),
    ('editor', '修谱编辑', '维护人物、关系、来源和修谱资料'),
    ('reviewer', '审核员', '负责资料复核、变更审核和定稿确认'),
    ('viewer', '查看者', '查看族谱、世系图谱和来源资料')
on conflict do nothing;

insert into app_role (role_code, role_name, description, system_role, created_at, updated_at)
values
    ('clan_admin', '宗族管理员', '管理宗族空间、用户角色、主数据、审核和全部业务配置', true, now(), now()),
    ('branch_admin', '支派管理员', '管理授权支派范围内的人物、关系、来源和支派数据', true, now(), now()),
    ('editor', '修谱编辑', '维护人物档案、世系关系、来源证据和修谱资料', true, now(), now()),
    ('reviewer', '审核员', '复核人物、关系、来源和入谱变更', true, now(), now()),
    ('viewer', '查看者', '仅可查看宗族、人物档案、世系图谱和来源资料，不允许新增、修改、审核和删除', true, now(), now())
on conflict (role_code) do update
set role_name = excluded.role_name,
    description = excluded.description,
    system_role = excluded.system_role,
    updated_at = now();

insert into app_user (username, phone, email, password_hash, display_name, avatar_url, status, last_login_at, created_at, updated_at, deleted_at)
values
    ('demo_admin', '13800000001', 'demo_admin@genealogy.local', convert_from(decode('50424b44463224313230303030245a3256755a574673623264354c57466b62576c754d513d3d2462334c6758504a6147737a752b65554669666b30753167633031472b737937306a78434f6c714262617a413d', 'hex'), 'UTF8'), '演示管理员', null, 'active', now() - interval '1 day', now(), now(), null),
    ('demo_editor', '13800000002', 'demo_editor@genealogy.local', convert_from(decode('50424b44463224313230303030245a3256755a574673623264354c57526c625738744d513d3d244a416f2b7079716b46594a4c4673746c57794f4e68734d712f692b4b4541654269616b71416965416a54553d', 'hex'), 'UTF8'), '演示编辑', null, 'active', now() - interval '2 days', now(), now(), null),
    ('demo_reviewer', '13800000003', 'demo_reviewer@genealogy.local', convert_from(decode('50424b44463224313230303030245a3256755a574673623264354c57526c625738744d513d3d244a416f2b7079716b46594a4c4673746c57794f4e68734d712f692b4b4541654269616b71416965416a54553d', 'hex'), 'UTF8'), '演示审核员', null, 'active', now() - interval '3 days', now(), now(), null),
    ('demo_viewer', '13800000004', 'demo_viewer@genealogy.local', convert_from(decode('50424b44463224313230303030245a3256755a574673623264354c585a705a58646c63673d3d2457665334345233325136486134372f76414734727553553948444d75672b6553305055554841424537636f3d', 'hex'), 'UTF8'), '演示查看者', null, 'active', now() - interval '4 days', now(), now(), null)
on conflict (username) do update
set phone = excluded.phone,
    email = excluded.email,
    password_hash = excluded.password_hash,
    display_name = excluded.display_name,
    avatar_url = excluded.avatar_url,
    status = 'active',
    last_login_at = excluded.last_login_at,
    updated_at = now(),
    deleted_at = null;

insert into user_account (username, phone, email, display_name, password_hash, status, created_at, last_login_at)
select username, phone, email, display_name, password_hash, status, created_at, last_login_at
from app_user
where username in ('demo_admin', 'demo_editor', 'demo_reviewer', 'demo_viewer');

insert into app_auth_session (user_id, token_hash, issued_at, expires_at, revoked_at, client_ip, user_agent)
select id,
       md5('seed-session-' || username),
       now() - interval '2 hours',
       now() + interval '22 hours',
       case when username = 'demo_viewer' then now() - interval '30 minutes' else null end,
       '127.0.0.1',
       'Flyway seed initializer'
from app_user
where username in ('demo_admin', 'demo_editor', 'demo_reviewer', 'demo_viewer');
